module accu(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output [9:0] data_out
);

reg [1:0] count;
reg [9:0] sum;
reg [1:0] next_count;
reg [9:0] next_sum;
reg next_valid_out;
reg [1:0] state;
parameter IDLE = 2'b00, INPUT = 2'b01, OUTPUT = 2'b10;
parameter NEXT_STATE_IDLE = 2'b00, NEXT_STATE_INPUT = 2'b01, NEXT_STATE_OUTPUT = 2'b10;

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        state <= IDLE;
        count <= 2'b00;
        sum <= 10'b0000000000;
        valid_out <= 1'b0;
    end else begin
        state <= next_state;
        count <= next_count;
        sum <= next_sum;
        valid_out <= next_valid_out;
    end
end

always @(*) begin
    next_state = state;
    next_count = count;
    next_sum = sum;
    next_valid_out = 1'b0;

    case(state)
        IDLE: begin
            if(valid_in) begin
                next_state = INPUT;
                next_count = 2'b00;
                next_sum = data_in;
            end
        end
        INPUT: begin
            if(count == 2'b11) begin
                next_state = OUTPUT;
                next_valid_out = 1'b1;
            end else begin
                next_count = count + 2'b01;
                next_sum = sum + data_in;
            end
        end
        OUTPUT: begin
            next_state = NEXT_STATE_IDLE;
            next_valid_out = 1'b1;
        end
        default: begin
            next_state = NEXT_STATE_IDLE;
        end
    endcase
end

assign data_out = sum;

endmodule
